import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { performLogin } from '../utils/login';
import styles from './Login.module.css';

const Login = () => {
  const [empNo, setEmpNo] = useState('admin');
  const [empPwd, setEmpPwd] = useState('new1234!');
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleLogin = async (e) => {
    e.preventDefault();
    setError('');
    await performLogin('web', empNo, empPwd, navigate, setError);
  };

  const handleMobileLoginRedirect = () => {
    navigate('/mobile/Login');
  };

  return (
    <div className={styles.loginContainer}>
      <h1 className={styles.title}>로그인</h1>
      <form onSubmit={handleLogin}>
        <div className={styles.formGroup}>
          <label htmlFor="userid" className={styles.label}>아이디</label>
          <input
            id="userid"
            type="text"
            value={empNo}
            onChange={(e) => setEmpNo(e.target.value)}
            placeholder="아이디를 입력하세요"
            required
            className={styles.input}
          />
        </div>
        <div className={styles.formGroup}>
          <label htmlFor="password" className={styles.label}>비밀번호</label>
          <input
            id="password"
            type="password"
            value={empPwd}
            onChange={(e) => setEmpPwd(e.target.value)}
            placeholder="비밀번호를 입력하세요"
            required
            className={styles.input}
          />
        </div>
        <button type="submit" className={styles.button}>Login</button>
        <h3/>
        <button 
          type="button" 
          className={styles.button}
          onClick={handleMobileLoginRedirect}
        >
          모바일로그인으로 이동
        </button>
      </form>
      {error && <p className={styles.error}>{error}</p>}
    </div>
  );
};

export default Login;